VALUES
  ('social-worker-moex-02711', 'social-worker', 'social-worker-moex-103-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '從團體的凝聚力可以了解團體的士氣、團隊精神、團體對成員的吸引力及團體進行中團員們的興趣等。 因此，有關團體凝聚力，領導者最適合用下列那一問題加以探討？', '["團體進行中有那些線索顯示成員們興趣缺缺或踴躍投入", "團體中領導者說過多少話？成員又說了多少", "為了進入團體，成員做了什麼準備", "那一些成員傾向於認同並支持某一位成員"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "41136ece6450", "answer_pdf_sha1": "71f6335f8306", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02712', 'social-worker', 'social-worker-moex-103-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '社會工作者對案主說：「對於你的案件進度緩慢，你好像感到非常生氣，而且開始懷疑你的努力是否會 成功？」，這樣的表達對照Hammond等人（1977）所提的五個同理反應層次，是屬於第三層次的同理反 應，請問其內涵下列何者錯誤？', '["社會工作者的口語或非口語表達已可與案主的明顯表達做相互交換", "此層次意圖要增加或減少案主所表達的表面感受", "此層次可引導案主做聚焦的反應", "社會工作者已可正確反應案主陳述中的事實部分"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "41136ece6450", "answer_pdf_sha1": "71f6335f8306", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02713', 'social-worker', 'social-worker-moex-103-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關認知重建取向的工作敘述，下列何者錯誤？', '["其最初的工作步驟是協助案主指認出產生失功能的認知情境", "對於案主產生新的自我陳述與行為，應協助給予獎賞", "「我沒有考好，我永遠進不了研究所」是一種全有全無的認知曲解", "社會工作者需留意認知重建有責備案主的可能性"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "41136ece6450", "answer_pdf_sha1": "71f6335f8306", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02714', 'social-worker', 'social-worker-moex-103-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '在會談過程中，有關「建議」的技巧使用，下列敘述何者正確？', '["建議的意涵即是指提供資訊", "建議的目的是影響案主採取或不採取某一種特定行為，是有立場偏好的", "「表明身分的第三人」是一種常用的建議技巧", "提建議將可以使案主與社會工作者兩者關係中的權力愈趨平等"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "41136ece6450", "answer_pdf_sha1": "71f6335f8306", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02715', 'social-worker', 'social-worker-moex-103-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關任務中心取向模式的敘述，下列何者錯誤？', '["此模式適用於處理多元文化的議題", "只想尋求心理支持與自我了解的案主，不適用此模式", "此模式的使用對於新進社會工作者的獨立作業能力是一大挑戰", "此模式對於非自願性案主非常適用"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "41136ece6450", "answer_pdf_sha1": "71f6335f8306", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02716', 'social-worker', 'social-worker-moex-103-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '社會工作者處理案主家庭關係的建構與平衡時所使用的工作方法中，下列那一項的使用需留意可能會受 到文化的影響，反而讓家庭產生困擾？', '["支持系統強化", "優點辨識", "家庭決策", "資源提供"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "41136ece6450", "answer_pdf_sha1": "71f6335f8306", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02717', 'social-worker', 'social-worker-moex-103-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關情感轉移的敘述，下列何者正確？', '["社會工作者若表現過量的了解與接納，通常會出現理想型的情感轉移", "在挫折型的情感轉移類型中，社會工作者通常被視為權威的象徵", "依賴型的情感轉移通常會出現在會談初期", "案主想模仿社會工作者，是指出現關愛型的情感轉移"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "41136ece6450", "answer_pdf_sha1": "71f6335f8306", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02718', 'social-worker', 'social-worker-moex-103-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '在與個案會談的技巧中，真實性（authenticity）是指社會工作者以一種誠實、開放與真誠的態度來分享自 己的感覺與期待，下列何者為真實性反應的工作要素？', '["以中立的態度來陳述所發生的情況", "將焦點放在案主的情緒管理", "以「你…」、「『你』感覺…」來呈現個人訊息", "對案主未說出口的感受加以反應"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "41136ece6450", "answer_pdf_sha1": "71f6335f8306", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02719', 'social-worker', 'social-worker-moex-103-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '調整案主的環境，以使案主的需求可以獲得滿足，這樣的工作方法我們稱為環境調整，下列何者不是環 境調整的工作項目？', '["強化家庭關係", "發展與強化家庭網絡", "訓練社交技巧", "改善機構環境"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "41136ece6450", "answer_pdf_sha1": "71f6335f8306", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02720', 'social-worker', 'social-worker-moex-103-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '個案工作者在進行轉介工作的過程中，必須做到的是：', '["幫助被轉介機構向案主做承諾或保證", "考量與決定何種資源最能滿足案主需要", "明確指出被轉介機構應如何協助案主", "轉介後持續與案主維持助人關係"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "41136ece6450", "answer_pdf_sha1": "71f6335f8306", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02721', 'social-worker', 'social-worker-moex-103-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '社會工作者在面對案主提供專業服務過程，經常會面臨進退兩難的情境，下列敘述何者錯誤？', '["屬於案主兩難的情境時，社會工作者直接將案主轉給另一位社會工作者處理", "屬於社會工作者兩難的情境時，社會工作者應具有高度敏感力，將面臨的專業價值兩難記錄並反省", "屬於案主兩難的情境時，社會工作者最好保持客觀、中立的態度", "屬於社會工作者兩難的情境時，評估此兩難是否影響專業關係的建立"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "41136ece6450", "answer_pdf_sha1": "71f6335f8306", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02722', 'social-worker', 'social-worker-moex-103-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '社會工作者在提供專業服務過程，必須恪守專業原則，其中有關案主自決原則係指：', '["試著了解案主的感受，並運用專業技巧，引導案主思考", "運用澄清技巧協助案主釐清所要表達的情緒、想法、意見或行為態度", "重視案主問題成因的個別差異，以及強調服務內涵的差異性", "運用沈默、減除焦慮等專業技巧，協助案主發展自我抉擇的能力"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "41136ece6450", "answer_pdf_sha1": "71f6335f8306", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02723', 'social-worker', 'social-worker-moex-103-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '運用危機介入（crisis intervention）模式於個案工作時，應遵守的原則是：', '["被動採取行動", "注入希望與期望", "無限的工作目標", "以處理情緒為目標"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "41136ece6450", "answer_pdf_sha1": "71f6335f8306", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02724', 'social-worker', 'social-worker-moex-103-694fe135', 'sub-social-worker-03', NULL, 'single_choice', 'Payne依照國際社會工作定義，指出社會工作者的工作有三面向，若有社會工作者說：「若可以提供協助 與服務來解決案主家庭問題，他們就可以更適當的配合社會的期待」，請問，其所使用的觀點是那一面 向？', '["治療觀點", "社會秩序觀點", "轉型觀點", "批判反思觀點"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "41136ece6450", "answer_pdf_sha1": "71f6335f8306", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02725', 'social-worker', 'social-worker-moex-103-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '在社會工作理論中，強調案主的不接受或逃避自由都是壞信念，應透過真誠面對，才能解放，引進人本 思想，視案主為一整體，請問該理論是：', '["解決焦點取向", "存在主義社會工作", "任務中心模型", "問題解決模型"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "41136ece6450", "answer_pdf_sha1": "71f6335f8306", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02726', 'social-worker', 'social-worker-moex-103-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關以證據為本（evidence-based）的社會工作敘述，下列何者錯誤？', '["其緣起主要是受到以證據為本的法律學之影響", "其強調社會工作者的決策最高原則是判斷什麼是有效的", "社會工作者應有研究心態，社會工作者也是研究者", "其可使社會工作者擺脫組織限制，獲得意識形態與技術的自由"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "41136ece6450", "answer_pdf_sha1": "71f6335f8306", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02727', 'social-worker', 'social-worker-moex-103-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '被推崇為「行政管理之父」，核心主張是控制幅度明確，指揮權統一，每個工作者只有一個老闆的學者 是：', '["韋伯（Max Weber）", "費堯（Henri Fayol）", "泰勒（Frederick Winslow Taylor）", "麥格雷特（Douglas McGregor）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "0cd65457bcf0", "answer_pdf_sha1": "68755a0548ae", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02728', 'social-worker', 'social-worker-moex-103-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '目標管理（MBO）為管理學大師彼得杜拉克（Peter F. Drucker）所倡導的管理方法，係指管理者以工作 「目標」來管理部屬，其對於促進員工生產力及導引個人的工作朝向組織目標有很多幫助。目標管理係 奠基於完善的人力資源管理四項要素，下列敘述何者錯誤？', '["目標的設定，係由高層管理者設定後再指派", "目標明確化，轉化成可以衡量評估的有形指標", "目標有一個明確的完成期間", "目標管理設有回饋機制，讓員工能隨時且持續的了解目標的達成程度"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "0cd65457bcf0", "answer_pdf_sha1": "68755a0548ae", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02729', 'social-worker', 'social-worker-moex-103-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '「最佳價值」主張藉由持續性的改善，使經濟（economy）、效率（efficiency）與效能（effectiveness）等 功能真正發揮。為了確保這樣的改善，必須透過不同項目來檢查他們的功能。這些檢查項目的字首均為 C， 不包括下列那一項敘述？', '["質疑（challenge）為什麼、如何及為誰而提供服務", "比較（compare）不同機構之間的績效", "就教（consult）於服務的使用者及地方社區", "儘可能溝通（communication）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "0cd65457bcf0", "answer_pdf_sha1": "68755a0548ae", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02730', 'social-worker', 'social-worker-moex-103-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '對方案規劃而言，有兩類型的評估：形成性評估（formative evaluation）與總結性評估（summative evaluation）。下列敘述那一項不符合形成性評估的特性？', '["在方案實際運作期間進行", "焦點在於過程目標", "回答關於方案在績效方面的問題", "確認服務是否提供給方案設計中所設定的服務對象"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "0cd65457bcf0", "answer_pdf_sha1": "68755a0548ae", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02731', 'social-worker', 'social-worker-moex-103-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '司徒達賢撰寫《非營利組織的經營管理》，對於非營利組織的走向與發展提出概念性架構，稱之為 「CORPS」，提供了一套簡易的管理邏輯思考。其中，社會工作管理者是組織決策的核心，其位置在CORPS 中扮演那一項元素的角色？', '["組合人力資源（Participants）", "找尋物力資源（Resources）", "執行有組織的活動（Operations）", "服務社會中的某些人（Clients）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "0cd65457bcf0", "answer_pdf_sha1": "68755a0548ae", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02732', 'social-worker', 'social-worker-moex-103-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '在所有需求評量方法當中，社會或社區調查可說是最強而有力的需求評量方法，能直接對社區蒐集資 料，也能取得消費者或潛在消費者心態方面的資訊。請問：這種社會調查是屬於下列那一種需求類型 的評量？', '["規範性需求", "感受性需求", "表達性需求", "相對性需求"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "0cd65457bcf0", "answer_pdf_sha1": "68755a0548ae", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02733', 'social-worker', 'social-worker-moex-103-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '「人群服務的專家們發現自己身處的時代，可以明顯辨別某一個案派給社會工作者的預期結果，可以追 蹤每一個案投入資源與努力的軌跡，並可以判斷是否達到預期的目標。又可以藉由許多個案所蒐集的資 料，發展出一套如何實際並有效率的幫助那些需要協助的人。」這說明了下列那一方面管理的重要性？', '["總務管理", "資訊管理", "資源管理", "服務管理"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "0cd65457bcf0", "answer_pdf_sha1": "68755a0548ae", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02734', 'social-worker', 'social-worker-moex-103-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '根據Martin（1993）相關著作，全面品質管理（total quality management, TQM）的哲學原理係有別於傳統 美國式管理之哲學原理。下列那一項敘述屬於全面品質管理之哲學原理？', '["組織有多重的競爭目標", "組織的財務主導組織", "消費者決定何謂品質", "鼓勵承約者以價格相互競爭"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "0cd65457bcf0", "answer_pdf_sha1": "68755a0548ae", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02735', 'social-worker', 'social-worker-moex-103-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '所謂的PDCA循環（計畫→行動→查核→處置，plan→do→check→action）的管理模式，其中「計畫」的 重點是策略的陳述、「行動」是策略的執行、「查核」代表評估與管制、「處置」是整體策略的完成。 此循環說明了下列那一項管理的重要性？', '["績效管理", "事務管理", "供應鍊管理", "品質管理"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "0cd65457bcf0", "answer_pdf_sha1": "68755a0548ae", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
